// Extract video ID from YouTube URL
const url = $input.first().json.youtubeUrl;
let videoId = '';

// Handle different YouTube URL formats
if (url.includes('youtube.com/watch?v=')) {
  videoId = url.split('v=')[1].split('&')[0];
} else if (url.includes('youtu.be/')) {
  videoId = url.split('youtu.be/')[1].split('?')[0];
} else if (url.includes('youtube.com/embed/')) {
  videoId = url.split('embed/')[1].split('?')[0];
}

return {
  videoId: videoId,
  originalUrl: url
};

// Process transcript data
const data = $input.first().json;

if (!data || !data.transcript) {
  return {
    success: false,
    error: 'No transcript available for this video',
    videoId: $('Extract Video ID1').item.json.videoId
  };
}

// Combine all transcript segments into full text
let fullTranscript = '';
let timestampedTranscript = [];

if (Array.isArray(data.transcript)) {
  data.transcript.forEach(segment => {
    if (segment.text) {
      fullTranscript += segment.text + ' ';

      // Keep timestamped version
      timestampedTranscript.push({
        time: segment.start || segment.offset || 0,
        text: segment.text
      });
    }
  });
}

// Clean up the transcript
const cleanedTranscript = fullTranscript
  .replace(/\s+/g, ' ')
  .replace(/\s([.,!?])/g, '$1')
  .trim();

return {
  success: true,
  videoId: $('Extract Video ID1').item.json.videoId,
  videoUrl: $('Extract Video ID1').item.json.originalUrl,
  fullTranscript: cleanedTranscript,
  timestampedTranscript: timestampedTranscript,
  wordCount: cleanedTranscript.split(' ').length,
  characterCount: cleanedTranscript.length,
  language: data.language || 'unknown'
};
